import{_ as e,o as i,c as s,ag as t}from"./chunks/framework.DXGyWiRo.js";const l="/images/deploy.png",g=JSON.parse('{"title":"Build & Deploy","description":"","frontmatter":{},"headers":[],"relativePath":"guide/deployment.md","filePath":"guide/deployment.md","lastUpdated":1776328915000}'),n={name:"guide/deployment.md"};function o(d,a,r,p,u,h){return i(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="build-deploy" tabindex="-1">Build &amp; Deploy <a class="header-anchor" href="#build-deploy" aria-label="Permalink to &quot;Build &amp; Deploy&quot;">​</a></h1><p><img src="'+l+'" alt="Deployment Illustration"></p><p>Setelah dokumentasi Anda siap, Anda perlu mem-build-nya menjadi file statis agar dapat dipublikasikan.</p><h2 id="membangun-situs-build" tabindex="-1">Membangun Situs (Build) <a class="header-anchor" href="#membangun-situs-build" aria-label="Permalink to &quot;Membangun Situs (Build)&quot;">​</a></h2><p>Jalankan perintah berikut untuk menghasilkan versi produksi dari situs Anda:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span></code></pre></div><p>Hasil build akan disimpan di folder <code>.vitepress/dist</code>. Folder ini berisi file HTML, CSS, dan JS statis yang siap di-hosting.</p><h2 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h2><p>VitePress dapat di-host di hampir semua layanan hosting statis.</p><h3 id="github-pages" tabindex="-1">GitHub Pages <a class="header-anchor" href="#github-pages" aria-label="Permalink to &quot;GitHub Pages&quot;">​</a></h3><ol><li>Pastikan kode Anda ada di repositori GitHub.</li><li>Gunakan GitHub Actions untuk mem-build dan men-deploy secara otomatis.</li><li>Anda bisa menggunakan template workflow resmi dari VitePress.</li></ol><h3 id="vercel-netlify" tabindex="-1">Vercel / Netlify <a class="header-anchor" href="#vercel-netlify" aria-label="Permalink to &quot;Vercel / Netlify&quot;">​</a></h3><ol><li>Hubungkan repositori Anda ke dashboard Vercel atau Netlify.</li><li>Atur Build Command: <code>npm run docs:build</code>.</li><li>Atur Output Directory: <code>.vitepress/dist</code>.</li><li>Klik Deploy!</li></ol><h3 id="cloudflare-pages" tabindex="-1">Cloudflare Pages <a class="header-anchor" href="#cloudflare-pages" aria-label="Permalink to &quot;Cloudflare Pages&quot;">​</a></h3><p>Untuk men-deploy VitePress ke Cloudflare Pages, gunakan pengaturan berikut di dashboard Cloudflare:</p><ol><li><strong>Framework Preset</strong>: <code>None</code> atau <code>Other</code>.</li><li><strong>Build command</strong>: <code>npm run docs:build</code>.</li><li><strong>Build output directory</strong>: <code>.vitepress/dist</code>.</li><li><strong>Root directory</strong>: <code>/</code> (Tetap biarkan default).</li></ol><p><strong>PENTING: Versi Node.js</strong> VitePress membutuhkan Node.js v18+. Di dashboard Cloudflare Pages, tambahkan <strong>Environment Variable</strong> berikut:</p><ul><li><strong>Variable name</strong>: <code>NODE_VERSION</code></li><li><strong>Variable value</strong>: <code>18</code> (atau lebih tinggi).</li></ul><p>Jika Anda menggunakan CLI (<strong>Wrangler</strong>), perintahnya adalah:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrangler</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pages</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .vitepress/dist</span></span></code></pre></div><h3 id="preview-lokal" tabindex="-1">Preview Lokal <a class="header-anchor" href="#preview-lokal" aria-label="Permalink to &quot;Preview Lokal&quot;">​</a></h3><p>Setelah melakukan build, Anda dapat mencoba melihat hasilnya secara lokal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:preview</span></span></code></pre></div>',23)])])}const k=e(n,[["render",o]]);export{g as __pageData,k as default};
